var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"오오, 뭐야? 뭐야? 이 갑옷 재질이 꽤 쌔끈한데?","JPN":"おお、何だ？　何だ？　この鎧の質感、結構イケてるな？","ENG":"Ooh, what's this? This armor feels really nice!","TWN":"噢噢，怎麼回事？這盔甲的材質蠻鋒利的呢？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L4_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"고생한 보람이 있군. 이런 고리타분한 전리품들은 또 어디 가서 구하기 힘들지.","JPN":"苦労した甲斐があったな。こんな古風な戦利品は他じゃ中々手に入るものじゃない。","ENG":"All our hard work finally paid off. You don't get these types of loot anywhere else.","TWN":"辛苦也是值得的。這種老式的戰利品去哪都很難買到呢。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"특수한 기술 체계를 사용하는군. 분석할 가치는 있다.","JPN":"特殊な技術体系を使っているようだ。分析の価値はある。","ENG":"They used an interesting technology system. It is worth analyzing.","TWN":"使用了特殊的技術系統，很有分析價值。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L7_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"흥. 이런 원시적인 녀석들이 위협이라니, 아이러니하기도 하지.","JPN":"ふん、こんな原始的な連中が脅威だなんて、皮肉な話だな。","ENG":"Hmph. To call these savages a threat is an irony.","TWN":"哼，這種原始的傢伙居然會成為威脅，真是諷刺。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_NULL","text":{"KOREA":"포격이다! 다들 엎드려!","JPN":"砲撃だ！　全員伏せろ！","ENG":"Incoming fire! Everyone, get down!","TWN":"有炮擊！大家趴下！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_NULL","text":{"KOREA":"저 강철 골렘, 화력이 끊이질 않아……!","JPN":"あの鋼鉄ゴーレム、火力がまったく衰えない……！","ENG":"That iron golem won't cease fire...!","TWN":"那個鋼鐵怪物，還沒停火過……！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"TITAN_FAW_ReinforcedA_NULL","text":{"KOREA":"으음! 굉장한 화력이군! 내 포신이 더욱 뜨겁게 타오르고 있다!","JPN":"うむ！　凄まじい火力だな！　吾輩の砲身がより熱く燃えている！","ENG":"Mmh! Great fire power! My gun barrel is heating up!","TWN":"呃嗯！好強的火力！我的炮身正在熊熊燃燒！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_ReinforcedA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"NAHEERIN_COFFIN_NULL_NULL","text":{"KOREA":"아뇨, 그거 오버히트인데요! 연사하시면 안 된다니까요, 정말!","JPN":"いいえ、それはオーバーヒートなのですよ！　連射はダメだって言ったじゃないですか、もう！","ENG":"I'm pretty sure it's overheating! You shouldn't auto fire, for goodness sake!","TWN":"那是過熱！過熱！都說了不能連著發射，真是的！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_ReinforcedA_NULL","face":"UNIT_IDLE"},"R":{"char_id":"NAHEERIN_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L18_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"대, 대장! 저기 대장이 있어!","JPN":"た、隊長！　あそこに隊長がいるよ！","ENG":"C-Cap! There she is!","TWN":"隊，隊長！隊長在那裡！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"피, 피투성이잖아? 대장을 얼마나 혹사시킨 거야?","JPN":"ち、血だらけ？　どれだけ酷使されたんだ、隊長？","ENG":"S-she's covered in blood! Just how much did they make her work?","TWN":"渾，渾身是血？隊長到底吃了多少苦頭？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"아냐, 얘들아. 난 괜찮으니까.","JPN":"いいえ、みんな。私は大丈夫。","ENG":"Guys, I'm fine.","TWN":"沒事，我沒事。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"너희들도…… 전부 무사했구나. 다행이야.","JPN":"みんなも……無事だったのね。よかった。","ENG":"You all seem fine as well... I'm glad.","TWN":"你們……也全都沒事，真是太好了。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"인사는 나중에 해.","JPN":"挨拶は後にして。","ENG":"We can greet each other later.","TWN":"不要再說話了。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"대장은 더 싸우기 힘들겠어. 우리가 후방으로 옮길게.","JPN":"隊長はもう戦えない。私たちが後方に連れて行く。","ENG":"You don't look like you're capable of fighting anymore. We'll move you to the back.","TWN":"你現在沒辦法繼續戰鬥，我們先把你移到後方。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"응. 잘 부탁해.","JPN":"うん、よろしく。","ENG":"Thank you.","TWN":"嗯，就交給你們了。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"푹 쉬세요, 서윤 양. 정신적으로나 육체적으로나 무리하셨으니까요.","JPN":"じっくり休んでください、シズカさん。精神的にも肉体的にも無理をしましたから。","ENG":"Get some rest, Seo Yoon. You have overworked yourself, both physically and mentally.","TWN":"你好好休息，徐芸。不管是精神上還是身體上，你都太逞強了。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"펜릴 소대, 들리나?","JPN":"フェンリル小隊、聞こえているか？","ENG":"Fenrir Squad, do you copy?","TWN":"芬里爾小隊，能聽到嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L31_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"여기는 펜릴 소대장. 그쪽도 무사히 도착했군.","JPN":"こちらフェンリル小隊長。そちらも無事に到着したようだな。","ENG":"Fenrir Commander speaking. I see you all have made it safe.","TWN":"我是芬里爾小隊長，看來你們也平安到達了。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"기적적으로 말이지.","JPN":"奇跡的にね。","ENG":"Miraculously.","TWN":"只能說是奇蹟。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L33_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"이 전쟁터는 우리 인류가 치러야 할 몫이다.","JPN":"この戦争は私たち人類の課題である。","ENG":"This battle is our burden to bear.","TWN":"這個戰場是我們人類理當面對的。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"너희는 가서 해야 할 일을 하도록.","JPN":"諸君はやるべきことをやれ。","ENG":"You go ahead and do what must be done.","TWN":"你們去做你們該做的事吧。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"……알겠다. 부탁하지.","JPN":"……わかった。頼んだぞ。","ENG":"...Understood. I leave the rest to you.","TWN":"……知道了，交給你們了。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};